// // This module implements a D flip-flop with asynchronous reset and synchronous enable. The output is set to one on the rising edge of the clock when the enable is high and the reset is active.
module top_module( input d, clk, rst, en, output reg q );always @( posedge clk)
		if(en)
			if (rst)
				q <= 0;
			else
				q <= d;
endmodule
